def list_recent_forecast_predictions(
    self,
    *,
    since: datetime,
    limit: int,
) -> list[ForecastPrediction]:
    with self.session() as s:
        return list(
            s.exec(
                select(ForecastPrediction)
                .where(ForecastPrediction.created_at >= since)
                .order_by(desc(ForecastPrediction.created_at))
                .limit(limit)
            ).all()
