%% else
\todomark{no peer-review swarm output found for the cluster's lead conclusion}
%% endif

%% if paper.peer_review.findings
\subsection*{Peer-review findings}
\begin{itemize}[leftmargin=1.5em]
%% for finding in paper.peer_review.findings
  \item \textbf{\VAR{finding.severity_tex}} --- \VAR{finding.detail_tex}
        \rowref{review\_report:\VAR{finding.report_id_tex}}
%% endfor
\end{itemize}
%% endif

\section{Limits and failure modes}
%% if paper.methodology.failure_modes
The methodology root carries a registered failure-mode catalog. Every
limit below is an entry from the firm's catalog, not a synthesized
observation.

\begin{itemize}[leftmargin=1.5em]
%% for fm in paper.methodology.failure_modes
  \item \VAR{fm}
%% endfor
\end{itemize}
%% else
\todomark{methodology root has no registered failure modes; manual review required before publication}
%% endif

\section{References}
\begin{enumerate}[leftmargin=2em]
%% for ref in paper.references
  \item \VAR{ref.text_tex} \rowref{\VAR{ref.row_kind_tex}:\VAR{ref.row_id_tex}}
%% endfor
%% if not paper.references
  \item \todomark{no citation rows associated with the cluster's conclusions}
%% endif
\end{enumerate}

\vfill
\begin{center}\small
\textit{This paper was machine-drafted by Theseus from the firm's existing
artifacts. Every numerical claim resolves to a row in the firm's
database (see \rowref{...} markers). The .tex source is the authoritative
artifact; the PDF is a build product.}
\end{center}

\end{document}

